var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"뭐지……? 이 불길한 느낌은?","JPN":"何だ……？　この不吉な感じは？","ENG":"What’s this ominous feeling...?","TWN":"怎麼回事……？有種不好的預感？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마, 뭔가 안 나타났어?","JPN":"おばさん、何か現れなかったの？","ENG":"Anything up, Maria?","TWN":"有出現什麼東西嗎，大嬸？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"침식체라거나, 적의 증원이라거나.","JPN":"侵食体とか、敵の増援とか。","ENG":"C.O.s, or more enemies?","TWN":"侵蝕體，還是敵人的增援？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"아니. 그런 동향은 없단다, 실비아.","JPN":"いや、そんな気配はないな、シルビア。","ENG":"No. There aren't any, Sylvia.","TWN":"不，沒有那方面的動向，希爾維亞。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"정말이야? 그렇다기에는 좀 이상하지 않아?","JPN":"本当？　でも何かがおかしくない？","ENG":"Really? Don't you think it's strange?","TWN":"真的嗎？那樣的話是不是有點奇怪？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"갑자기 교전에 관련된 통신이 완전히 멎어 버렸어.","JPN":"いきなり交戦に関しての通信が完全に途絶えた。","ENG":"All communications regarding battles have gone completely silent.","TWN":"關於交戰的通訊突然間完全停止了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금 이 일대에서 아무도 싸우지 않는다는 말이라고! 이해가 돼?","JPN":"今この一帯では誰ひとり戦ってないってことなのよ！　おかしくない？","ENG":"It means that no one is fighting in the surrounding area! Do you get me?","TWN":"也就是說現在的這一刻沒有發生任何打鬥！有可能嗎？"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"승조원들도 다들 불안해하고 있어. 다들 말 한마디 못하고 서로 눈치만 보고 있다고.","JPN":"乗組員たちもみんな不安がってる。みんな固まってお互いの様子だけ見ているわ。","ENG":"Everyone here is feeling anxious. They keep looking at each other, quiet as a mouse.","TWN":"艦上人員也都很不安。大家都一言不發地看著彼此的眼色。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"적들도 움직임이 완전히 멎었어요.","JPN":"敵の動きも完全に止まりました。","ENG":"Even the enemies have completely stopped moving.","TWN":"敵人也完全停止了行動。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"저희와 같이 굉장히… 긴장하고 있는 것처럼 보여요.","JPN":"私たちと同じく……緊張しているように見えます。","ENG":"They look... tensed up, like we are.","TWN":"看起來和我們一樣……好像也非常緊張。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"……싸우지 않는 게 아니야.","JPN":"……戦わないんじゃない。","ENG":"...It's not that they stopped fighting.","TWN":"……不是不打了。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"뭔가 거대한……. 적 따위가 아니라, 재해가 닥쳐 오는 걸 아는데도 막지 못하는 기분이군.","JPN":"何か巨大な……、敵なんかじゃない、災害が押し寄せてくるのを知りながら止めようがないときの気分だ。","ENG":"I feel... as if a giant... unstoppable disaster is coming. Something much more than an enemy.","TWN":"有種明知道某種不是敵人的……巨大災難要來了，卻無法阻止的感覺。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MARIA_DELTA_NEXT_NULL","text":{"KOREA":"이런 묘한 분위기 속에서…… 한가하게 싸울 수 있을 리 없지.","JPN":"こんな妙な雰囲気の中じゃ……戦う気にもなれない。","ENG":"No one would be able to fight... in this sinister atmosphere.","TWN":"在這種詭譎的氣氛中……當然不可能還打得下去。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"MARIA_DELTA_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIFLE_ADMIN_NULL_NULL","text":{"KOREA":"전대장님, 이건…….","JPN":"戦隊長、これは……","ENG":"Commander, this is...","TWN":"戰隊長，這是……"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"그래. 침식파도, CRF도…. 아무것도 느껴지지 않지만.","JPN":"ええ、侵食派も、CRFも……何も感じないけど。","ENG":"Yes. There is neither Corruption ray, nor CRF...","TWN":"是的，雖然感受不到任何侵蝕波……或CRF。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"뭔가 오고 있다. 와서는 안 될 무언가가.","JPN":"何かが来ている。来てはいけない何かが。","ENG":"But something's coming. Something that shouldn't be here.","TWN":"但是有什麼東西正在過來，不該過來的某種東西。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ARTILLERY_ADMIN_NEXT_NULL","text":{"KOREA":"……관리자님께서 말씀하신 대로야.","JPN":"……管理者様の言う通りだ。","ENG":"...It's just as the Administrator said.","TWN":"……就像管理者說的那樣。"},"stage":{"bg":"COUNTERSIDE_ASH","slots":{"L":null,"C":{"char_id":"ARTILLERY_ADMIN_NEXT_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};